import React, { useState, useCallback } from 'react';
import { DataConnection } from '../../types';

interface EditorElement {
  id: string;
  type: 'shape' | 'text' | 'button';
  position: { x: number; y: number };
  size: { width: number; height: number };
  properties: {
    // Shape properties
    shapeType?: 'rectangle' | 'circle' | 'line';
    fillColor?: string;
    borderColor?: string;
    borderWidth?: number;
    
    // Text properties
    text?: string;
    fontSize?: number;
    fontColor?: string;
    fontWeight?: string;
    
    // Button properties
    buttonText?: string;
    backgroundColor?: string;
    linkedVariable?: string;
    onClick?: string; // JavaScript code to execute
  };
}

interface CodeEditorConfig {
  id: string;
  name: string;
  elements: EditorElement[];
  htmlCode: string;
  jsCode: string;
  cssCode: string;
}

interface CodeEditorProps {
  dataConnections: DataConnection;
  onDataConnectionsChange: (dataConnections: DataConnection) => void;
  configs: CodeEditorConfig[];
  onConfigsChange: (configs: CodeEditorConfig[]) => void;
}

const CodeEditor: React.FC<CodeEditorProps> = ({
  dataConnections,
  onDataConnectionsChange,
  configs,
  onConfigsChange
}) => {
  const [activeConfig, setActiveConfig] = useState<string | null>(configs[0]?.id || null);
  const [selectedElement, setSelectedElement] = useState<string | null>(null);
  const [dragState, setDragState] = useState<{
    isDragging: boolean;
    elementId: string | null;
    startX: number;
    startY: number;
    startElementX: number;
    startElementY: number;
  }>({
    isDragging: false,
    elementId: null,
    startX: 0,
    startY: 0,
    startElementX: 0,
    startElementY: 0
  });

  const currentConfig = configs.find(c => c.id === activeConfig);

  const createNewConfig = () => {
    const newConfig: CodeEditorConfig = {
      id: `config-${Date.now()}`,
      name: `Editor ${configs.length + 1}`,
      elements: [],
      htmlCode: '',
      jsCode: '',
      cssCode: ''
    };
    onConfigsChange([...configs, newConfig]);
    setActiveConfig(newConfig.id);
  };

  const addElement = (type: 'shape' | 'text' | 'button') => {
    if (!currentConfig) return;

    const newElement: EditorElement = {
      id: `element-${Date.now()}`,
      type,
      position: { x: 100, y: 100 },
      size: { width: type === 'text' ? 150 : 100, height: type === 'text' ? 30 : 50 },
      properties: {
        ...(type === 'shape' && {
          shapeType: 'rectangle',
          fillColor: '#007bff',
          borderColor: '#0056b3',
          borderWidth: 2
        }),
        ...(type === 'text' && {
          text: 'Sample Text',
          fontSize: 16,
          fontColor: '#333333',
          fontWeight: 'normal'
        }),
        ...(type === 'button' && {
          buttonText: 'Button',
          backgroundColor: '#28a745',
          linkedVariable: '',
          onClick: ''
        })
      }
    };

    const updatedConfig = {
      ...currentConfig,
      elements: [...currentConfig.elements, newElement]
    };

    onConfigsChange(configs.map(c => c.id === activeConfig ? updatedConfig : c));
  };

  const generateCode = () => {
    if (!currentConfig) return;

    let html = '<div class="editor-container">\n';
    let css = '.editor-container { position: relative; width: 100%; height: 400px; }\n';
    let js = '// Generated JavaScript\n';

    currentConfig.elements.forEach(element => {
      const { position, size, properties } = element;
      
      if (element.type === 'shape') {
        const shapeClass = `shape-${element.id}`;
        html += `  <div class="${shapeClass}"></div>\n`;
        
        css += `.${shapeClass} {\n`;
        css += `  position: absolute;\n`;
        css += `  left: ${position.x}px;\n`;
        css += `  top: ${position.y}px;\n`;
        css += `  width: ${size.width}px;\n`;
        css += `  height: ${size.height}px;\n`;
        css += `  background-color: ${properties.fillColor};\n`;
        css += `  border: ${properties.borderWidth}px solid ${properties.borderColor};\n`;
        if (properties.shapeType === 'circle') {
          css += `  border-radius: 50%;\n`;
        }
        css += `}\n`;
      }
      
      if (element.type === 'text') {
        const textClass = `text-${element.id}`;
        html += `  <div class="${textClass}">${properties.text}</div>\n`;
        
        css += `.${textClass} {\n`;
        css += `  position: absolute;\n`;
        css += `  left: ${position.x}px;\n`;
        css += `  top: ${position.y}px;\n`;
        css += `  font-size: ${properties.fontSize}px;\n`;
        css += `  color: ${properties.fontColor};\n`;
        css += `  font-weight: ${properties.fontWeight};\n`;
        css += `}\n`;
      }
      
      if (element.type === 'button') {
        const buttonClass = `button-${element.id}`;
        html += `  <button class="${buttonClass}" onclick="handleButton_${element.id}()">${properties.buttonText}</button>\n`;
        
        css += `.${buttonClass} {\n`;
        css += `  position: absolute;\n`;
        css += `  left: ${position.x}px;\n`;
        css += `  top: ${position.y}px;\n`;
        css += `  width: ${size.width}px;\n`;
        css += `  height: ${size.height}px;\n`;
        css += `  background-color: ${properties.backgroundColor};\n`;
        css += `  border: none;\n`;
        css += `  color: white;\n`;
        css += `  cursor: pointer;\n`;
        css += `}\n`;
        
        js += `function handleButton_${element.id}() {\n`;
        if (properties.linkedVariable) {
          js += `  // Linked to global variable: ${properties.linkedVariable}\n`;
        }
        if (properties.onClick) {
          js += `  ${properties.onClick}\n`;
        } else {
          js += `  console.log('Button ${element.id} clicked');\n`;
        }
        js += `}\n\n`;
      }
    });

    html += '</div>';

    const updatedConfig = {
      ...currentConfig,
      htmlCode: html,
      jsCode: js,
      cssCode: css
    };

    onConfigsChange(configs.map(c => c.id === activeConfig ? updatedConfig : c));
  };

  const handleMouseDown = (e: React.MouseEvent, elementId: string) => {
    e.stopPropagation();
    setSelectedElement(elementId);
    
    const element = currentConfig?.elements.find(el => el.id === elementId);
    if (!element) return;

    setDragState({
      isDragging: true,
      elementId,
      startX: e.clientX,
      startY: e.clientY,
      startElementX: element.position.x,
      startElementY: element.position.y
    });
  };

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!dragState.isDragging || !currentConfig) return;

    const deltaX = e.clientX - dragState.startX;
    const deltaY = e.clientY - dragState.startY;
    const newX = dragState.startElementX + deltaX;
    const newY = dragState.startElementY + deltaY;

    const updatedElements = currentConfig.elements.map(element => 
      element.id === dragState.elementId 
        ? { ...element, position: { x: Math.max(0, newX), y: Math.max(0, newY) } }
        : element
    );

    const updatedConfig = { ...currentConfig, elements: updatedElements };
    onConfigsChange(configs.map(c => c.id === activeConfig ? updatedConfig : c));
  }, [dragState, currentConfig, configs, activeConfig, onConfigsChange]);

  const handleMouseUp = useCallback(() => {
    setDragState({
      isDragging: false,
      elementId: null,
      startX: 0,
      startY: 0,
      startElementX: 0,
      startElementY: 0
    });
  }, []);

  React.useEffect(() => {
    if (dragState.isDragging) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      return () => {
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
      };
    }
  }, [dragState.isDragging, handleMouseMove, handleMouseUp]);

  const renderElement = (element: EditorElement) => {
    const isSelected = selectedElement === element.id;
    const style: React.CSSProperties = {
      position: 'absolute',
      left: element.position.x,
      top: element.position.y,
      width: element.size.width,
      height: element.size.height,
      cursor: 'move',
      border: isSelected ? '2px solid #007bff' : 'none',
      boxSizing: 'border-box'
    };

    if (element.type === 'shape') {
      return (
        <div
          key={element.id}
          style={{
            ...style,
            backgroundColor: element.properties.fillColor,
            border: `${element.properties.borderWidth}px solid ${element.properties.borderColor}`,
            borderRadius: element.properties.shapeType === 'circle' ? '50%' : '0',
            ...(isSelected && { boxShadow: '0 0 0 2px #007bff' })
          }}
          onMouseDown={(e) => handleMouseDown(e, element.id)}
        />
      );
    }

    if (element.type === 'text') {
      return (
        <div
          key={element.id}
          style={{
            ...style,
            fontSize: element.properties.fontSize,
            color: element.properties.fontColor,
            fontWeight: element.properties.fontWeight,
            display: 'flex',
            alignItems: 'center',
            padding: '4px',
            ...(isSelected && { border: '2px solid #007bff' })
          }}
          onMouseDown={(e) => handleMouseDown(e, element.id)}
        >
          {element.properties.text}
        </div>
      );
    }

    if (element.type === 'button') {
      return (
        <button
          key={element.id}
          style={{
            ...style,
            backgroundColor: element.properties.backgroundColor,
            color: 'white',
            border: 'none',
            cursor: 'move',
            ...(isSelected && { border: '2px solid #007bff' })
          }}
          onMouseDown={(e) => handleMouseDown(e, element.id)}
        >
          {element.properties.buttonText}
        </button>
      );
    }

    return null;
  };

  return (
    <div style={{ display: 'flex', height: '100%', fontFamily: '"Segoe UI", "Arial", sans-serif' }}>
      {/* Left Panel - Tools */}
      <div style={{ 
        width: '250px', 
        backgroundColor: '#f7f8fa', 
        borderRight: '1px solid #dee2e6',
        padding: '20px'
      }}>
        <h3 style={{ margin: '0 0 20px 0', fontSize: '18px', color: '#333' }}>Code Editor</h3>
        
        {/* Configuration Management */}
        <div style={{ marginBottom: '20px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '10px' }}>
            <select 
              value={activeConfig || ''}
              onChange={(e) => setActiveConfig(e.target.value)}
              style={{ flex: 1, padding: '8px', border: '1px solid #ccc', borderRadius: '4px' }}
            >
              {configs.map(config => (
                <option key={config.id} value={config.id}>{config.name}</option>
              ))}
            </select>
            <button
              onClick={createNewConfig}
              style={{
                padding: '8px 12px',
                backgroundColor: '#007bff',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer'
              }}
            >
              New
            </button>
          </div>
        </div>

        {/* Tools */}
        <div style={{ marginBottom: '20px' }}>
          <h4 style={{ margin: '0 0 10px 0', fontSize: '14px', color: '#666' }}>Add Elements</h4>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            <button
              onClick={() => addElement('shape')}
              style={{
                padding: '8px 12px',
                backgroundColor: '#28a745',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer'
              }}
            >
              + Shape
            </button>
            <button
              onClick={() => addElement('text')}
              style={{
                padding: '8px 12px',
                backgroundColor: '#6f42c1',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer'
              }}
            >
              + Text
            </button>
            <button
              onClick={() => addElement('button')}
              style={{
                padding: '8px 12px',
                backgroundColor: '#fd7e14',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer'
              }}
            >
              + Button
            </button>
          </div>
        </div>

        {/* Generate Code */}
        <button
          onClick={generateCode}
          style={{
            width: '100%',
            padding: '12px',
            backgroundColor: '#17a2b8',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer',
            fontSize: '14px',
            fontWeight: '600'
          }}
        >
          Generate Code
        </button>

        {/* Global Variables */}
        <div style={{ marginTop: '20px' }}>
          <h4 style={{ margin: '0 0 10px 0', fontSize: '14px', color: '#666' }}>Global Variables</h4>
          <div style={{ maxHeight: '150px', overflowY: 'auto' }}>
            {Object.keys(dataConnections.globalVariables).map(varName => (
              <div
                key={varName}
                style={{
                  padding: '4px 8px',
                  backgroundColor: '#e9ecef',
                  borderRadius: '3px',
                  margin: '2px 0',
                  fontSize: '12px',
                  color: '#495057'
                }}
              >
                {varName}: {String(dataConnections.globalVariables[varName])}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
        {/* Canvas */}
        <div style={{ flex: 1, display: 'flex' }}>
          {/* Visual Editor */}
          <div style={{ flex: 1, backgroundColor: '#ffffff', position: 'relative', overflow: 'hidden' }}>
            <div style={{ 
              padding: '10px',
              backgroundColor: '#f8f9fa',
              borderBottom: '1px solid #dee2e6',
              fontSize: '14px',
              fontWeight: '600'
            }}>
              Visual Editor - {currentConfig?.name || 'No Configuration'}
            </div>
            <div 
              style={{ 
                position: 'relative', 
                width: '100%', 
                height: 'calc(100% - 45px)',
                backgroundColor: '#fafafa'
              }}
              onClick={() => setSelectedElement(null)}
            >
              {currentConfig?.elements.map(renderElement)}
            </div>
          </div>

          {/* Code Preview */}
          <div style={{ width: '400px', backgroundColor: '#f8f9fa', borderLeft: '1px solid #dee2e6' }}>
            <div style={{ 
              padding: '10px',
              backgroundColor: '#343a40',
              color: 'white',
              fontSize: '14px',
              fontWeight: '600'
            }}>
              Generated Code
            </div>
            <div style={{ height: 'calc(100% - 45px)', overflow: 'auto', padding: '10px' }}>
              {currentConfig && (
                <>
                  <div style={{ marginBottom: '20px' }}>
                    <h5 style={{ margin: '0 0 10px 0', color: '#495057' }}>HTML</h5>
                    <pre style={{ 
                      backgroundColor: '#f1f3f4', 
                      padding: '10px', 
                      borderRadius: '4px',
                      fontSize: '12px',
                      overflow: 'auto'
                    }}>
                      {currentConfig.htmlCode || '// Click "Generate Code" to create HTML'}
                    </pre>
                  </div>
                  <div style={{ marginBottom: '20px' }}>
                    <h5 style={{ margin: '0 0 10px 0', color: '#495057' }}>CSS</h5>
                    <pre style={{ 
                      backgroundColor: '#f1f3f4', 
                      padding: '10px', 
                      borderRadius: '4px',
                      fontSize: '12px',
                      overflow: 'auto'
                    }}>
                      {currentConfig.cssCode || '// Click "Generate Code" to create CSS'}
                    </pre>
                  </div>
                  <div>
                    <h5 style={{ margin: '0 0 10px 0', color: '#495057' }}>JavaScript</h5>
                    <pre style={{ 
                      backgroundColor: '#f1f3f4', 
                      padding: '10px', 
                      borderRadius: '4px',
                      fontSize: '12px',
                      overflow: 'auto'
                    }}>
                      {currentConfig.jsCode || '// Click "Generate Code" to create JavaScript'}
                    </pre>
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CodeEditor;